var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"헉, 헉…! 어서 지원 보내 달라고 회사에 연락해!","JPN":"はあ、はっ……！　早く支援を送ってくれと会社に連絡しろ！","ENG":"*Huff... Huff...* Call the company for backup, now!","TWN":"呼，呼…！快通知公司派支援來！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"젠장, 침식체들이 어디서 이렇게 많이 나타난 거야?","JPN":"くそ、どこからこんな大量の侵食体が現れやがったんだ？","ENG":"Dammit! Where are all these C.O.s coming from?","TWN":"該死，從哪冒出來這麼多的侵蝕體？"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"대체 얼마나 죽어 나간 거야…. 그 괴물은 또 뭐냐고!","JPN":"いったい何人死んだんだ……あのバケモンはまた何なんだよ！","ENG":"How many of them have we killed...? And what the hell is that monster?!","TWN":"到底死了多少人…那個怪物又是什麼鬼！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아저씨, 여기라면 안전할 거예요. 우리 잠깐만 쉬어요.","JPN":"おじさん、ここなら安全です。ちょっとだけ休みましょう？","ENG":"Mister, I think we're safe here. Let's rest here a little.","TWN":"大叔，這裡應該很安全，我們休息一下吧。"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"그, 그래.","JPN":"あ、ああ。","ENG":"S-sure.","TWN":"嗯，好。"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"덕분에 살았어…. 네 무기, 보기보다 위력이 대단하더라.","JPN":"おかげで助かった……お前の武器、見た目よりすごい威力だな。","ENG":"I'm still alive thanks to you... Your weapon is a lot stronger than it looks.","TWN":"幸好有你，我才能保住小命… 你的武器實際上比看起來還威呢。"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗. 네. 천사님도 이게 절 지켜 줄 거라고 하셨거든요.","JPN":"あっ、はい。天使様もこの武器が私を守ってくれるっておっしゃってました。","ENG":"Oh, yes. The angel told me that it would protect me.","TWN":"是啊，天使也說這個可以保護我。"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"여행을 다닐 때는 위험한 일들이 많이 일어난다면서요.","JPN":"旅の途中には危ないことがいっぱい起きるからって。","ENG":"She said that danger lurks in every corner when you are traveling.","TWN":"旅行的時候經常會發生許多危險的事呢。"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"천사님…?","JPN":"天使様……？","ENG":"Angel...?","TWN":"天使…？"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"어~이!","JPN":"おーい！","ENG":"Hey!","TWN":"有～人～嗎！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어? 저 목소리는…?","JPN":"あれ？　あの声は……？","ENG":"Huh? Isn't that voice...?","TWN":"嗯？這個聲音是…？"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"어이! 다들 어디 있는 거야!","JPN":"おい！　みんなどこだ！","ENG":"Hey! Where are ya guys?","TWN":"喂！大家在哪！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"침식체들은 이미 가 버렸어! 이제 숨어 있지 않아도 돼!","JPN":"侵食体どもはもういなくなったぞ！　隠れなくても大丈夫だ！","ENG":"The C.O.s are gone! You can come out now!","TWN":"侵蝕體都離開了！不用再躲了！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"저… 저 친구? 살아 있었나?","JPN":"あ……あいつ？　生きてたのか？","ENG":"H-how is it that... he's still alive?","TWN":"是…我朋友？他還活著嗎？"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_COMPLETE_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아저씨, 안 돼요! 아까 피를 흘리면서 쓰러지는 모습 보셨잖아요!","JPN":"おじさん、ダメです！　さっき血を流しながら倒れる姿を見たじゃないですか！","ENG":"Mister, No! You saw him fall down bleeding.","TWN":"大叔，不可以！你剛不是也有看到他流血倒下嗎！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"다, 닥쳐 봐! 내 친구 목소리야!","JPN":"だ、黙れ！　俺のダチの声に違いねえ！","ENG":"S-shut up! That's my friend's voice! I'm certain of it!","TWN":"住，住口！那是我朋友的聲音！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_COMPLETE_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"다들 집에 안 갈 거야? 어서 나와!","JPN":"みんな、家に帰らねえのか？　早く出て来いよ！","ENG":"Aren't y'all gonna go home? Let's go!","TWN":"我們回家吧？你們快出來！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"다친 사람 목소리치고는 너무 멀쩡하잖아요! 이상해요!","JPN":"怪我人の声にしてはあまりにも元気すぎます！　おかしいですよ！","ENG":"He sounds too well for someone who was injured! That's weird!","TWN":"一個受傷的人聲音會那麼有力嗎！不對勁！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"빌어먹을…! 확인만 하고 오면 되잖아! 확인만!","JPN":"くそ……！　確認するくらいいいだろ！　確認だけ！","ENG":"Dammit...! At least let me check if it's him or not!","TWN":"該死…！我去看一下總可以吧！確認一下就好！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_COMPLETE_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"저리 비켜!","JPN":"どけ！","ENG":"Out of the way!","TWN":"走開！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_COMPLETE_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"꺄악!?","JPN":"きゃあっ！？","ENG":"Eeek!","TWN":"欸！？"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"이봐! 살아 있었으면 무전이라도 보내지!","JPN":"おい！　生きてたんなら無線でも入れろよ！","ENG":"Hey! You should've radioed if you were okay!","TWN":"喂！你沒死的話好歹也傳個無線電給我吧！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L30_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"……어? 뭐, 뭐야, 이 살덩어리는……?","JPN":"……あ？　な、何だ、この肉の塊は……？","ENG":"...W-what? W-what's this lump of flesh...?","TWN":"……唔？你，你，這肉塊是……？"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"오지 마! 오지 말라고! 아악! 아아아아아악!!","JPN":"来るな！　来るな！　ああ！　ああああああ！！","ENG":"S-stay back! Get away from me!! AAAGH!!","TWN":"別怪來！走開！啊啊啊啊啊！！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_C","text":{"KOREA":"비, 빌어먹을…. 뭐가 어떻게 된 거야….","JPN":"く、くそ……何がどうなってんだ……","ENG":"H-holy crap... What's going on...?","TWN":"該，該死的…是發生什麼事…"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_D","text":{"KOREA":"아까 창밖을 엿보는데 커다란 진흙 더미 같은 게 뒷골목으로 들어가고 있었어.","JPN":"さっき窓の外を見たんだけど、大きな泥の山みたいなのが路地裏に入って行ったぞ。","ENG":"I took a peek out the window and saw a big pile of mud go into the back alleyway.","TWN":"我剛偷看一下窗外，看到超大的泥團往後巷那裡移動。"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_D","face":"UNIT_IDLE"},"C":{"char_id":"MERCENARY_NPC_ESPR2_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_D","text":{"KOREA":"어쩌면 그 괴물 놈이 죽은 사람들 시체를 반죽해서 조종하는 걸지도 몰라.","JPN":"もしかしたらあの化け物が死んだやつらの体を塊にして操ってるのかも知れねえ。","ENG":"Maybe that monster is battering up the corpses into one and controlling it.","TWN":"我猜那個怪物應該是把死人的屍體弄成一團後控制它們。"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_D","face":"UNIT_IDLE"},"C":{"char_id":"MERCENARY_NPC_ESPR2_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_C","text":{"KOREA":"무서운 소리 하지 마…! 가뜩이나 다리도 부러진 마당에!","JPN":"怖いこと言うな……！　足も折れてるってのに！","ENG":"You're freaking me out, man! I've already got a broken leg!","TWN":"你不要嚇我…！而且我現在腿斷掉欸！"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_D","face":"UNIT_IDLE"},"C":{"char_id":"MERCENARY_NPC_ESPR2_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으, 으아아……. 어떡하지…….","JPN":"う、うわあ……どうしよう……","ENG":"U-uaaah... What do we do...?","TWN":"呃呃呃……怎麼辦……"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"여, 여보세요? 누구세요?","JPN":"も、もしもし？　どちら様ですか？","ENG":"H-hello? Who's this?","TWN":"喂，喂？請問哪位？"},"stage":{"bg":"CLOSE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"간신히 연락이 닿았군. 노엘 양.","JPN":"やっと連絡がついたな。ノエル君。","ENG":"You finally answered, Noelle.","TWN":"終於聯絡上你了，洛艾兒小姐。"},"stage":{"bg":"CLOSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L44_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사장님! 코핀 컴퍼니 사장님 맞으시죠?","JPN":"社長！　コフィンカンパニーの社長ですよね？","ENG":"Boss? This is Coffin Company's boss, right?","TWN":"老闆！請問是科芬公司的老闆沒錯吧？"},"stage":{"bg":"CLOSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다네. 한 번 만났을 뿐인데 잘 기억하고 있군.","JPN":"そうだ。一度会っただけなのに、よく憶えているな。","ENG":"Correct. I'm flattered you remember me even though we only met briefly.","TWN":"沒錯，我們才見過一次面而已，你記性很好呢。"},"stage":{"bg":"CLOSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저, 저기, 이런 상황에 부탁하긴 좀 그런데 번호 저장해 둬도 될까요?","JPN":"あ、あの、こんな状況で言うのもちょっとあれなんですけど、番号を登録しておいてもいいですか？","ENG":"Um... I know this might sound out of place, but can I save this number on my phone?","TWN":"那個，現在提出這種要求有點奇怪，不過我可以儲存老闆的電話號碼嗎？"},"stage":{"bg":"CLOSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론이고 말고.","JPN":"もちろんだとも。","ENG":"Of course, you may.","TWN":"當然可以。"},"stage":{"bg":"CLOSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그나저나 곤경에 처한 모양인데, 어떤가?","JPN":"それより困っているようだが？","ENG":"Anyway, I believe you're in trouble. How's the situation?","TWN":"不過你現在似乎遇到困難，是嗎？"},"stage":{"bg":"CLOSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으음…. 그게요.","JPN":"うーん……それがですね。","ENG":"Um... well...","TWN":"嗯…對啊。"},"stage":{"bg":"CLOSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"같이 온 용병 분들 중에 다친 분들이 계세요.","JPN":"一緒に来た傭兵の方の中に、怪我をした人がいるんですよ。","ENG":"Some of the mercenaries that I came here with are badly injured.","TWN":"一起作戰的傭兵之中有人受傷，"},"stage":{"bg":"CLOSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"밖에는 커다란 침식체가 돌아다녀서, 함부로 나갔다간 큰일나겠어요.","JPN":"外には大きな侵食体がうろついてて、出て行ったら大変なことになりそうです。","ENG":"And there's this huge C.O. outside, so we can't just go out and run.","TWN":"可是外面又有侵蝕體，我怕亂跑出去的話會出事。"},"stage":{"bg":"CLOSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저 혼자서라면 어떻게든 따돌려 보겠지만… 그러다간 다른 분들이 위험해질 거 같아요.","JPN":"私一人なら何とかして撒けばいいんですけど……そうすると他の人たちが危険になりそうで。","ENG":"I could get away from it if I was alone... But then, the others will be in danger.","TWN":"只有我自己一個的話，還可以想辦法甩掉它們…但其他人就會有危險。"},"stage":{"bg":"CLOSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 상황은 이해했네.","JPN":"よし。状況は理解した。","ENG":"Okay. I understand the situation.","TWN":"好，我明白什麼情況了。"},"stage":{"bg":"CLOSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금 우리 직원들이 그쪽으로 가는 중일세.","JPN":"今、うちの社員たちがそちらに向かっている。","ENG":"One of our employees is heading there as we speak.","TWN":"我的員工正往那裡移動。"},"stage":{"bg":"CAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 가만히 있다간 인명피해가 더 늘어나겠지.","JPN":"だが、そこに留まっていれば人的被害がさらに増すだろう。","ENG":"But more will get hurt if you just stay put.","TWN":"但我怕什麼也不做的話會有更多人員傷亡。"},"stage":{"bg":"VEHICLE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"노엘 양, 그 침식체를 부상자들과 멀리 떨어진 곳으로 유인할 수 있겠나?","JPN":"ノエル君、その侵食体を怪我人から遠く離れたところに誘導することはできるかい？","ENG":"Noelle, do you think you can lure that C.O. far away from the others?","TWN":"洛艾兒小姐，你可以將侵蝕體引到離傷者遠一點的地方嗎？"},"stage":{"bg":"CLOSE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"유인이요?","JPN":"誘導ですか？","ENG":"Lure?","TWN":"引開侵蝕體嗎？"},"stage":{"bg":"CLOSE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 가까운 곳에 교량이 있을 걸세.","JPN":"そう。近くに橋があるはずだ。","ENG":"Yes. There should be a bridge nearby.","TWN":"沒錯，附近應該有座橋，"},"stage":{"bg":"CLOSE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그라운드 원에서 자네가 있는 구역으로 들어가는 통로지.","JPN":"グラウンド・ワンから君のいる区域に入る通路さ。","ENG":"It is also the passageway to there from Ground One.","TWN":"是從G1通往你所在地區的通道。"},"stage":{"bg":"CLOSE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어떤가, 할 수 있겠나?","JPN":"どうだ、できるかい？","ENG":"What do you think? Do you think you can do it?","TWN":"怎麼樣？你可以嗎？"},"stage":{"bg":"CLOSE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"……네! 물론이죠! 해 보겠습니다!","JPN":"……はい！　もちろんです！　やってみます！","ENG":"...Sure, absolutely! I'll do my best!","TWN":"……是！當然可以！交給我！"},"stage":{"bg":"CLOSE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"믿음직스럽군. 그럼 잘 부탁하겠네.","JPN":"頼もしいな。それでは、よろしく頼むぞ。","ENG":"Perfect. I knew I could trust you.","TWN":"真是可靠，那就拜託你囉。"},"stage":{"bg":"CLOSE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}}]`);export{e as default};